"use client";

/**
 * Section 01 — the night's PA announcements, set large. These are the lines
 * that smear: each English line is a .plaza-ab element whose cyan and pink
 * pseudo-element ghosts split apart with scroll velocity (see styles.css and
 * useScrollEnergy). The base glyphs never move and never lose contrast — the
 * ghosts are additive light on top, so the aberration can only make the text
 * brighter, never dimmer.
 */

const NOTES = [
  {
    time: "00:12",
    en: "The doors are locked. The lights are on. We take that personally.",
    ko: "문은 잠겼고, 불은 켜져 있습니다. 우리는 그걸 진심으로 받아들입니다.",
  },
  {
    time: "01:47",
    en: "Tonight’s special: everything you left behind, half off.",
    ko: "오늘 밤 특가 — 당신이 두고 간 모든 것, 반값.",
  },
  {
    time: "02:58",
    en: "Parking level B3 does not exist between three and four.",
    ko: "지하 3층 주차장은 3시부터 4시까지 존재하지 않습니다.",
  },
  {
    time: "04:26",
    en: "The food court closes when you stop remembering it.",
    ko: "푸드코트는 당신이 잊는 순간 문을 닫습니다.",
  },
  {
    time: "05:55",
    en: "If you can hear this, the mall is open. For you.",
    ko: "이 방송이 들린다면, 몰은 영업 중입니다. 당신만을 위해.",
    last: true,
  },
] as const;

export default function Announcements() {
  return (
    <section className="plaza-section plaza-pa" aria-labelledby="plaza-pa-title">
      <div className="plaza-sechead">
        <p className="plaza-sechead__no" aria-hidden="true">
          01
        </p>
        <h2
          id="plaza-pa-title"
          className="plaza-sechead__title plaza-ab"
          data-text="ANNOUNCEMENTS"
        >
          ANNOUNCEMENTS{" "}
          <span lang="ko" className="plaza-sechead__ko">
            오늘 밤의 안내방송
          </span>
        </h2>
        <p className="plaza-sechead__meta">
          scroll fast and the PA smears like a tired CRT ·{" "}
          <span lang="ko">빠르게 스크롤하면 방송이 브라운관처럼 번집니다</span>
        </p>
      </div>

      <ul className="plaza-pa__list">
        {NOTES.map((note) => (
          <li
            key={note.time}
            className={`plaza-pa__item${"last" in note && note.last ? " plaza-pa__item--last" : ""}`}
          >
            <span className="plaza-pa__time">{note.time} AM</span>
            <p className="plaza-pa__en plaza-ab" data-text={note.en}>
              {note.en}
            </p>
            <p className="plaza-pa__ko" lang="ko">
              {note.ko}
            </p>
          </li>
        ))}
      </ul>
    </section>
  );
}

"use client";

import { useEffect, useRef, type RefObject } from "react";

/** Backing-store cap — neon lines gain nothing above 2. */
const MAX_DPR = 2;
/** Grid scroll speed in lane-units/second: at rest, and added at full rush. */
const BASE_SPEED = 0.5;
const RUSH_SPEED = 4.2;
/** Projection constant: screen depth d = NEAR / z (z in lane units). */
const NEAR = 0.92;
/** Horizontal grid rows evaluated per frame. */
const ROWS = 26;
/** Reduced motion renders exactly one composed frame at this time/offset. */
const STILL_TIME = 28_000;
const STILL_OFFSET = 0.42;

type Star = {
  x: number;
  y: number;
  r: number;
  base: number;
  tw: number;
  phase: number;
  drift: number;
};

type Props = {
  reduced: boolean;
  /** Live scroll energy 0→1 from useScrollEnergy — read inside rAF only. */
  energyRef: RefObject<number>;
};

/**
 * The signature scene: an infinite perspective grid floor on a DPR-capped
 * 2D canvas — striped gradient sun, drifting star particles, and a horizon
 * that glows harder the faster you scroll. The grid always drifts gently on
 * its own (so touch devices get a living floor without hovering anything);
 * scroll velocity multiplies the speed up to ~9× and the floor rushes.
 *
 * The rAF loop pauses when the hero leaves the viewport and when the tab
 * hides. Reduced motion draws one composed still frame and never loops.
 * A CSS gradient sky sits underneath as the no-JS view, so the hero is
 * never a black rectangle.
 */
export default function Hero({ reduced, energyRef }: Props) {
  const stageRef = useRef<HTMLElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let raf = 0;
    let running = false;
    let visible = true;
    let last = 0;
    let time = reduced ? STILL_TIME : 0;
    let offset = STILL_OFFSET;
    let w = 0;
    let h = 0;
    let dpr = 1;
    let stars: Star[] = [];

    const makeStars = () => {
      const skyH = h * 0.58;
      const count = Math.min(200, Math.round((w * skyH) / 6500));
      stars = Array.from({ length: count }, () => ({
        x: Math.random() * w,
        y: Math.random() * skyH * 0.94,
        r: Math.random() < 0.12 ? 2 : 1.2,
        base: 0.2 + Math.random() * 0.55,
        tw: 0.0003 + Math.random() * 0.0014,
        phase: Math.random() * Math.PI * 2,
        drift: 0.002 + Math.random() * 0.006, // px per ms, leftward
      }));
    };

    const resize = () => {
      const rect = stage.getBoundingClientRect();
      dpr = Math.min(window.devicePixelRatio || 1, MAX_DPR);
      w = Math.max(1, rect.width);
      h = Math.max(1, rect.height);
      canvas.width = Math.round(w * dpr);
      canvas.height = Math.round(h * dpr);
      makeStars();
    };

    const draw = (t: number, off: number, energy: number) => {
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      const horizon = h * 0.58;
      const cx = w / 2;

      // -- sky ------------------------------------------------------------
      const sky = ctx.createLinearGradient(0, 0, 0, horizon);
      sky.addColorStop(0, "#0d0518");
      sky.addColorStop(0.6, "#1a0b2e");
      sky.addColorStop(1, "#2b1152");
      ctx.fillStyle = sky;
      ctx.fillRect(0, 0, w, horizon);

      // -- stars: position is a pure function of t, so the reduced-motion
      //    still frame is simply one honest moment of the same sky --------
      ctx.fillStyle = "#efe6ff";
      for (const s of stars) {
        const x = (((s.x - t * s.drift) % w) + w) % w;
        ctx.globalAlpha = s.base * (0.55 + 0.45 * Math.sin(t * s.tw + s.phase));
        ctx.fillRect(x, s.y, s.r, s.r);
      }
      ctx.globalAlpha = 1;

      // -- sun halo (breathes a little wider when you rush) ---------------
      const sunR = Math.min(w, h) * 0.2;
      const sunX = cx;
      const sunY = horizon - sunR * 0.3;
      const halo = ctx.createRadialGradient(
        sunX,
        sunY,
        sunR * 0.3,
        sunX,
        sunY,
        sunR * 2.5,
      );
      halo.addColorStop(0, `rgba(255, 113, 206, ${(0.3 + energy * 0.2).toFixed(3)})`);
      halo.addColorStop(1, "rgba(255, 113, 206, 0)");
      ctx.fillStyle = halo;
      ctx.fillRect(0, 0, w, horizon);

      // -- sun disc in 2px slices; venetian blinds widen toward the floor -
      for (let dy = -sunR; dy < sunR; dy += 2) {
        const y = sunY + dy;
        if (y >= horizon) break; // the sun sets behind the grid
        if (dy > 0) {
          const period = 9 + dy * 0.55;
          if (dy % period < 2.5 + dy * 0.14) continue; // blind gap
        }
        const half = Math.sqrt(sunR * sunR - dy * dy);
        const m = (dy + sunR) / (2 * sunR); // pink → violet, top to bottom
        ctx.fillStyle = `rgb(${Math.round(255 - 70 * m)} ${Math.round(
          113 - 10 * m,
        )} ${Math.round(206 + 49 * m)})`;
        ctx.fillRect(sunX - half, y, half * 2, 2);
      }

      // -- floor ------------------------------------------------------------
      const floor = ctx.createLinearGradient(0, horizon, 0, h);
      floor.addColorStop(0, "#170a31");
      floor.addColorStop(1, "#0d0518");
      ctx.fillStyle = floor;
      ctx.fillRect(0, horizon, w, h - horizon);

      // -- vertical rays: every lane converges on the vanishing point ------
      const fade = ctx.createLinearGradient(0, horizon, 0, h);
      fade.addColorStop(0, "rgba(1, 205, 254, 0)");
      fade.addColorStop(0.16, "rgba(1, 205, 254, 0.3)");
      fade.addColorStop(1, `rgba(1, 205, 254, ${(0.42 + energy * 0.3).toFixed(3)})`);
      ctx.strokeStyle = fade;
      ctx.lineWidth = 1;
      const laneW = Math.max(w * 0.07, 48);
      const lanes = Math.ceil((w * 0.75) / laneW) + 2;
      ctx.beginPath();
      for (let i = -lanes; i <= lanes; i++) {
        ctx.moveTo(cx, horizon);
        ctx.lineTo(cx + i * laneW * 1.9, h + 2);
      }
      ctx.stroke();

      // -- horizontal rows sliding down the projection ----------------------
      const frac = off % 1;
      for (let j = 0; j < ROWS; j++) {
        const z = j + 1 - frac;
        if (z < NEAR) continue; // this row has already passed the camera
        const d = NEAR / z; // 1 at the bottom edge → 0 at the horizon
        const y = horizon + (h - horizon) * d;
        const a = Math.min(0.8, d * 0.9) * (0.55 + energy * 0.45);
        ctx.strokeStyle = `rgba(1, 205, 254, ${a.toFixed(3)})`;
        ctx.lineWidth = 1 + d * 1.6;
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(w, y);
        ctx.stroke();
      }

      // -- horizon glow: the part that rushes with you ----------------------
      const g = 0.3 + energy * 0.55;
      const glow = ctx.createLinearGradient(0, horizon - 30, 0, horizon + 24);
      glow.addColorStop(0, "rgba(5, 255, 161, 0)");
      glow.addColorStop(0.55, `rgba(5, 255, 161, ${(0.38 * g).toFixed(3)})`);
      glow.addColorStop(1, "rgba(1, 205, 254, 0)");
      ctx.fillStyle = glow;
      ctx.fillRect(0, horizon - 30, w, 54);
      ctx.fillStyle = `rgba(5, 255, 161, ${Math.min(1, 0.5 + energy * 0.5).toFixed(3)})`;
      ctx.fillRect(0, horizon - 1, w, 1.25);
    };

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 64);
      last = now;
      time += dt;
      const energy = energyRef.current;
      offset += (dt / 1000) * (BASE_SPEED + energy * RUSH_SPEED);
      draw(time, offset, energy);
    };

    const shouldRun = () => !reduced && visible && !document.hidden;

    const sync = () => {
      if (shouldRun()) {
        if (!running) {
          running = true;
          last = performance.now();
          raf = requestAnimationFrame(step);
        }
      } else if (running) {
        running = false;
        cancelAnimationFrame(raf);
      }
    };

    const onVisibility = () => sync();

    resize();
    draw(time, offset, 0); // first frame now — also the reduced-motion still

    const io = new IntersectionObserver(
      (hits) => {
        visible = hits[hits.length - 1].isIntersecting;
        sync();
      },
      { rootMargin: "60px 0px" },
    );
    io.observe(stage);

    const ro = new ResizeObserver(() => {
      resize();
      if (!running) draw(time, offset, 0);
    });
    ro.observe(stage);

    document.addEventListener("visibilitychange", onVisibility);
    sync();

    return () => {
      running = false;
      cancelAnimationFrame(raf);
      io.disconnect();
      ro.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [reduced, energyRef]);

  return (
    <header ref={stageRef} className="plaza-hero">
      <div className="plaza-hero__backdrop" aria-hidden="true" />
      <canvas
        ref={canvasRef}
        className="plaza-hero__canvas"
        role="img"
        aria-label="A neon perspective grid floor rushes toward a striped gradient sun on the horizon of an empty mall. 텅 빈 쇼핑몰의 지평선 — 네온 원근 그리드 바닥이 줄무늬 석양을 향해 달려간다."
      />
      <div className="plaza-hero__content">
        <p className="plaza-hero__station">
          <span className="plaza-onair">
            <span className="plaza-onair__lamp" aria-hidden="true" />
            ON AIR
          </span>
          <span className="plaza-hero__freq">
            FM 88.8 · midnight mall radio
          </span>
        </p>
        <h1 className="plaza-hero__title plaza-ab" data-text="GRADIENT PLAZA">
          GRADIENT PLAZA
        </h1>
        <p className="plaza-hero__sub" lang="ko">
          미드나잇 몰 라디오 — 그라디언트 플라자
        </p>
        <p className="plaza-hero__line">
          Broadcasting nightly from a shopping mall that only exists after
          closing.{" "}
          <span lang="ko" className="plaza-hero__ko">
            폐점 후에만 존재하는 쇼핑몰에서, 매일 밤 송출 중.
          </span>
        </p>
        <p className="plaza-hero__hint">
          scroll — the floor rushes ·{" "}
          <span lang="ko">스크롤 — 바닥이 달립니다</span>
        </p>
      </div>
    </header>
  );
}

"use client";

import { useEffect, useRef, type RefObject } from "react";

/** Ticker speed in px/second: resting drift, and what full rush adds. */
const BASE_PX_S = 42;
const RUSH_PX_S = 300;

const LINES = [
  {
    en: "Attention shoppers: the escalators run all night, for no one.",
    ko: "안내 말씀드립니다 — 에스컬레이터는 밤새 운행합니다, 아무도 없이.",
  },
  {
    en: "The fountain accepts wishes until 4 AM. Exact change only.",
    ko: "분수는 새벽 4시까지 소원을 받습니다. 동전은 정확히 준비해 주세요.",
  },
  {
    en: "Please do not feed the mannequins.",
    ko: "마네킹에게 먹이를 주지 마세요.",
  },
  {
    en: "Lost and found is now found and lost.",
    ko: "분실물 센터는 이제 스스로를 분실했습니다.",
  },
  {
    en: "Weather inside the mall: fluorescent, with rain expected in the food court.",
    ko: "몰 내부 날씨 — 형광등 맑음, 푸드코트에는 비 소식.",
  },
] as const;

type Props = {
  reduced: boolean;
  /** Live scroll energy 0→1 — the PA reads faster when you run. */
  energyRef: RefObject<number>;
};

/**
 * The PA ticker: one JS-driven marquee whose speed is coupled to scroll
 * energy — stroll and the announcements drift by; rush and the PA hurries
 * after you. The moving track is aria-hidden and duplicated once for a
 * seamless wrap; screen readers get the announcements exactly once from a
 * visually-hidden list. Without JavaScript (or with reduced motion) the
 * strip is simply a static line of announcements.
 */
export default function PAMarquee({ reduced, energyRef }: Props) {
  const clipRef = useRef<HTMLDivElement | null>(null);
  const trackRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (reduced) return;
    const clip = clipRef.current;
    const track = trackRef.current;
    if (!clip || !track) return;

    let raf = 0;
    let running = false;
    let visible = true;
    let x = 0;
    let runW = 0;
    let last = 0;

    const measure = () => {
      runW = track.scrollWidth / 2; // two identical runs
    };

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 64);
      last = now;
      x -= (dt / 1000) * (BASE_PX_S + energyRef.current * RUSH_PX_S);
      if (runW > 0 && -x >= runW) x += runW;
      track.style.transform = `translate3d(${x.toFixed(2)}px, 0, 0)`;
    };

    const sync = () => {
      const should = visible && !document.hidden;
      if (should && !running) {
        running = true;
        last = performance.now();
        raf = requestAnimationFrame(step);
      } else if (!should && running) {
        running = false;
        cancelAnimationFrame(raf);
      }
    };

    const onVisibility = () => sync();

    const io = new IntersectionObserver((hits) => {
      visible = hits[hits.length - 1].isIntersecting;
      sync();
    });
    io.observe(clip);

    // The track is sized by its content (width: max-content), so this also
    // fires when the webfonts land and the runs get wider.
    const ro = new ResizeObserver(measure);
    ro.observe(track);

    document.addEventListener("visibilitychange", onVisibility);
    measure();
    sync();

    return () => {
      running = false;
      cancelAnimationFrame(raf);
      io.disconnect();
      ro.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
      track.style.transform = "";
    };
  }, [reduced, energyRef]);

  return (
    <div className="plaza-ticker">
      <ul className="plaza-sr">
        {LINES.map((line) => (
          <li key={line.en}>
            {line.en} <span lang="ko">{line.ko}</span>
          </li>
        ))}
      </ul>
      <div ref={clipRef} className="plaza-ticker__clip" aria-hidden="true">
        <div ref={trackRef} className="plaza-ticker__track">
          {[0, 1].map((copy) => (
            <div key={copy} className="plaza-ticker__run">
              {LINES.map((line) => (
                <span key={line.en} className="plaza-ticker__item">
                  <span className="plaza-ticker__mark">✦</span>
                  {line.en} <span lang="ko">{line.ko}</span>
                </span>
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import {
  useEffect,
  useRef,
  useState,
  type ReactNode,
  type RefObject,
} from "react";
import { useDrag } from "../hooks/useDrag";

type WindowId = "now" | "list" | "viz";

const WINDOW_META: Record<WindowId, { title: string; ko: string }> = {
  now: { title: "NOWPLAYING.EXE", ko: "지금 나오는 곡" },
  list: { title: "TRACKLIST.TXT", ko: "선곡표" },
  viz: { title: "VISUALIZER.EXE", ko: "비주얼라이저" },
};

const TRACKS = [
  {
    title: "Escalator to Nowhere",
    ko: "어디로도 가지 않는 에스컬레이터",
    artist: "Plaza Muzak Ensemble",
    artistKo: "플라자 무자크 앙상블",
    len: "4:52",
  },
  {
    title: "Fountain Coins (Wet Mix)",
    ko: "분수 동전 (웻 믹스)",
    artist: "Miss Foodcourt",
    artistKo: "미스 푸드코트",
    len: "3:33",
  },
  {
    title: "Anchor Store Heart",
    ko: "폐점한 백화점의 심장",
    artist: "New Sincerity Dept.",
    artistKo: "신성실 백화점부",
    len: "6:07",
  },
  {
    title: "B3 Slow Dance",
    ko: "지하 3층 슬로 댄스",
    artist: "The Escalators",
    artistKo: "디 에스컬레이터스",
    len: "5:19",
  },
  {
    title: "Last Bus Home",
    ko: "막차",
    artist: "Plaza Muzak Ensemble",
    artistKo: "플라자 무자크 앙상블",
    len: "4:04",
  },
] as const;

/**
 * Section 02 — the booth: three retro-OS windows over a tiled stage.
 * Drag them by the title bar (pointer or touch; release keeps a little
 * momentum), move the focused title bar with arrow keys (Shift = fine,
 * Home = respawn), click anywhere on a window to raise it. Minimize and
 * close are real buttons; closed windows come back from the taskbar.
 * Without JavaScript the windows simply stack in the document flow with
 * every track and label readable — dragging is enhancement, not content.
 */
export default function RadioWindows({ reduced }: { reduced: boolean }) {
  const stageRef = useRef<HTMLDivElement | null>(null);
  const [stack, setStack] = useState<WindowId[]>(["viz", "list", "now"]);
  const [open, setOpen] = useState<Record<WindowId, boolean>>({
    now: true,
    list: true,
    viz: true,
  });
  const [track, setTrack] = useState(0);

  const raise = (id: WindowId) =>
    setStack((s) =>
      s[s.length - 1] === id ? s : [...s.filter((w) => w !== id), id],
    );

  const close = (id: WindowId) => setOpen((o) => ({ ...o, [id]: false }));

  const toggle = (id: WindowId) => {
    setOpen((o) => ({ ...o, [id]: !o[id] }));
    raise(id);
  };

  const current = TRACKS[track];
  const prevTrack = () => setTrack((i) => (i + TRACKS.length - 1) % TRACKS.length);
  const nextTrack = () => setTrack((i) => (i + 1) % TRACKS.length);

  return (
    <section className="plaza-section plaza-booth" aria-labelledby="plaza-booth-title">
      <div className="plaza-sechead">
        <p className="plaza-sechead__no" aria-hidden="true">
          02
        </p>
        <h2
          id="plaza-booth-title"
          className="plaza-sechead__title plaza-ab"
          data-text="THE BOOTH"
        >
          THE BOOTH{" "}
          <span lang="ko" className="plaza-sechead__ko">
            방송 부스
          </span>
        </h2>
        <p className="plaza-sechead__meta">
          drag the windows · focus a title bar and steer with arrow keys ·{" "}
          <span lang="ko">창을 드래그하세요 · 타이틀 바에 포커스 후 화살표 키로 이동</span>
        </p>
      </div>

      <div ref={stageRef} className="plaza-stage">
        <PlazaWindow
          id="now"
          z={stack.indexOf("now")}
          open={open.now}
          stageRef={stageRef}
          reduced={reduced}
          onRaise={raise}
          onClose={close}
        >
          <p className="plaza-now__label">
            NOW PLAYING · <span lang="ko">지금 나오는 곡</span>
          </p>
          <p className="plaza-now__track">{current.title}</p>
          <p className="plaza-now__trackko" lang="ko">
            {current.ko}
          </p>
          <p className="plaza-now__artist">
            {current.artist} · <span lang="ko">{current.artistKo}</span>
          </p>
          <div className="plaza-now__progress" aria-hidden="true">
            <span className="plaza-now__fill" />
          </div>
          <p className="plaza-now__time">
            02:14 / {current.len} — looping until dawn ·{" "}
            <span lang="ko">동틀 때까지 반복</span>
          </p>
          <div className="plaza-now__controls">
            <button
              type="button"
              className="plaza-btn"
              onClick={prevTrack}
              aria-label="Previous track / 이전 곡"
            >
