          </div>
        </PlazaWindow>

        <PlazaWindow
          id="list"
          z={stack.indexOf("list")}
          open={open.list}
          stageRef={stageRef}
          reduced={reduced}
          onRaise={raise}
          onClose={close}
        >
          <ul className="plaza-list">
            {TRACKS.map((t, i) => (
              <li key={t.title}>
                <button
                  type="button"
                  className="plaza-list__item"
