"use client";

import {
  useRef,
  type KeyboardEvent,
  type PointerEvent,
  type RefObject,
} from "react";

/** Keyboard nudge in px; hold Shift for fine placement. */
const KEY_STEP = 24;
const KEY_STEP_FINE = 4;
/** Inertia: exponential decay per 60fps-normalized frame. */
const FRICTION = 0.9;
/** Glide parks below this speed (px/ms). */
const STOP_SPEED = 0.02;
/** How far a window may tuck past the stage's side/bottom edges. */
const EDGE = 16;

type Bounds = { minX: number; maxX: number; minY: number; maxY: number };

type DragOptions = {
  /** The element that gets translated (the whole window). */
  windowRef: RefObject<HTMLElement | null>;
  /** The positioned stage the window is clamped inside. */
  stageRef: RefObject<HTMLElement | null>;
  /** Reduced motion: dragging still works (user-driven), inertia does not. */
  reduced: boolean;
  /** Called on grab / keyboard move — the parent raises the window. */
  onActivate?: () => void;
};

export type DragHandlers = {
  onPointerDown: (e: PointerEvent<HTMLElement>) => void;
  onPointerMove: (e: PointerEvent<HTMLElement>) => void;
  onPointerUp: (e: PointerEvent<HTMLElement>) => void;
  onPointerCancel: (e: PointerEvent<HTMLElement>) => void;
  onKeyDown: (e: KeyboardEvent<HTMLElement>) => void;
};

/**
 * Pointer + keyboard dragging for the retro OS windows, transform-only.
 *
 * The grip captures its pointer (setPointerCapture), so moves keep arriving
 * even when the cursor leaves the title bar; position is written as
 * translate3d on the window element — never left/top, so a drag costs the
 * compositor, not layout. Release keeps a little momentum (friction 0.9 per
 * normalized frame) unless reduced motion asked for none. Arrow keys move
 * the focused grip in 24px tiles (Shift = 4px), Home sends the window back
 * to its spawn point. Bounds are measured once per grab, not per move.
 */
export function useDrag({
  windowRef,
  stageRef,
  reduced,
  onActivate,
}: DragOptions): DragHandlers {
  const pos = useRef({ x: 0, y: 0 });
  const vel = useRef({ x: 0, y: 0 });
  const rafRef = useRef(0);
  const bounds = useRef<Bounds>({ minX: -1e5, maxX: 1e5, minY: -1e5, maxY: 1e5 });
  const grab = useRef<{
    id: number;
    px: number;
    py: number;
    bx: number;
    by: number;
    lx: number;
    ly: number;
    lt: number;
  } | null>(null);

  const measure = () => {
    const el = windowRef.current;
    const stage = stageRef.current;
    if (!el || !stage) return;
    const minX = -el.offsetLeft - EDGE;
    const minY = -el.offsetTop;
    bounds.current = {
      minX,
      maxX: Math.max(minX, stage.clientWidth - el.offsetLeft - el.offsetWidth + EDGE),
      minY,
      maxY: Math.max(minY, stage.clientHeight - el.offsetTop - el.offsetHeight + EDGE),
    };
  };

  const apply = () => {
    const el = windowRef.current;
    if (el) {
      el.style.transform = `translate3d(${pos.current.x.toFixed(2)}px, ${pos.current.y.toFixed(2)}px, 0)`;
    }
  };

  /** Clamp into bounds; reports which axes hit a wall (to kill momentum). */
  const clampPos = () => {
    const b = bounds.current;
    const p = pos.current;
    const cx = Math.min(b.maxX, Math.max(b.minX, p.x));
    const cy = Math.min(b.maxY, Math.max(b.minY, p.y));
    const hit = { x: cx !== p.x, y: cy !== p.y };
    p.x = cx;
    p.y = cy;
    return hit;
  };

  const stopGlide = () => cancelAnimationFrame(rafRef.current);

  const glide = () => {
    let lastT = performance.now();
    const step = (now: number) => {
      // Window unmounted mid-glide: nothing left to move — stop quietly.
      if (!windowRef.current) return;
      const dt = Math.min(Math.max(now - lastT, 1), 64);
      lastT = now;
      pos.current.x += vel.current.x * dt;
      pos.current.y += vel.current.y * dt;
      const hit = clampPos();
      if (hit.x) vel.current.x = 0;
      if (hit.y) vel.current.y = 0;
      const decay = Math.pow(FRICTION, dt / 16.7);
      vel.current.x *= decay;
      vel.current.y *= decay;
      apply();
      if (Math.hypot(vel.current.x, vel.current.y) > STOP_SPEED) {
        rafRef.current = requestAnimationFrame(step);
      }
    };
    rafRef.current = requestAnimationFrame(step);
  };

  const onPointerDown = (e: PointerEvent<HTMLElement>) => {
    if (e.pointerType === "mouse" && e.button !== 0) return;
    onActivate?.();
    stopGlide();
    measure();
    e.currentTarget.setPointerCapture(e.pointerId);
    grab.current = {
      id: e.pointerId,
      px: e.clientX,
      py: e.clientY,
      bx: pos.current.x,
      by: pos.current.y,
      lx: e.clientX,
      ly: e.clientY,
      lt: performance.now(),
    };
    vel.current = { x: 0, y: 0 };
  };

  const onPointerMove = (e: PointerEvent<HTMLElement>) => {
    const g = grab.current;
    if (!g || e.pointerId !== g.id) return;
    pos.current.x = g.bx + (e.clientX - g.px);
    pos.current.y = g.by + (e.clientY - g.py);
    clampPos();
    apply();
    const now = performance.now();
    const dt = now - g.lt;
    if (dt > 12) {
      vel.current = { x: (e.clientX - g.lx) / dt, y: (e.clientY - g.ly) / dt };
      g.lx = e.clientX;
      g.ly = e.clientY;
      g.lt = now;
    }
  };

  const endDrag = (e: PointerEvent<HTMLElement>) => {
    const g = grab.current;
    if (!g || e.pointerId !== g.id) return;
    grab.current = null;
    if (!reduced && Math.hypot(vel.current.x, vel.current.y) > STOP_SPEED * 3) {
      glide();
    }
  };

  const onKeyDown = (e: KeyboardEvent<HTMLElement>) => {
    const step = e.shiftKey ? KEY_STEP_FINE : KEY_STEP;
    let dx = 0;
    let dy = 0;
    switch (e.key) {
      case "ArrowLeft":
        dx = -step;
        break;
      case "ArrowRight":
        dx = step;
        break;
      case "ArrowUp":
        dy = -step;
        break;
      case "ArrowDown":
        dy = step;
        break;
      case "Home": {
        e.preventDefault();
        onActivate?.();
        stopGlide();
        pos.current = { x: 0, y: 0 };
        apply();
        return;
      }
      default:
        return;
    }
    e.preventDefault();
    onActivate?.();
    stopGlide();
    measure();
    pos.current.x += dx;
    pos.current.y += dy;
    clampPos();
    apply();
  };

  return {
    onPointerDown,
    onPointerMove,
    onPointerUp: endDrag,
    onPointerCancel: endDrag,
    onKeyDown,
  };
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 * When it is true the mall holds still: the grid floor freezes on one frame,
 * the aberration ghosts never appear, the ticker parks, and windows move
 * only when the visitor moves them.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef, type RefObject } from "react";

/** Scroll speed (px/ms) that counts as a full-tilt rush down the corridor. */
const V_MAX = 2.4;
/** Energy attack / release per 60fps-normalized frame — the floor notices
 *  you fast and calms down slowly, like a PA echo dying in an atrium. */
const ATTACK = 0.16;
const RELEASE = 0.05;
/** Chromatic aberration envelope: max RGB-split offset and ghost opacity. */
const MAX_SHIFT_PX = 7;
const MAX_GHOST = 0.85;
/** Below this energy, after this much scroll silence, the loop parks. */
const SLEEP_AT = 0.004;
const SLEEP_AFTER_MS = 320;

/**
 * Turns page scroll VELOCITY (not position) into a smoothed 0→1 "energy".
 *
 * Two consumers, one number:
 *   - CSS: writes --plaza-shift (px) and --plaza-ghost (opacity) on the entry
 *     root; the .plaza-ab pseudo-element ghosts translate/fade with them, so
 *     fast scrolling smears headings like a de-converged CRT.
 *   - JS: the returned ref is read inside the grid-floor and ticker rAF
 *     loops to modulate their speed — scroll faster, the floor rushes.
 *
 * The loop only runs while there is something to decay: it wakes on the
 * first scroll event and parks itself once energy has drained, so an idle
 * page costs zero frames. Under prefers-reduced-motion the hook writes the
 * resting values once and never listens at all.
 */
export function useScrollEnergy(
  rootRef: RefObject<HTMLElement | null>,
  reduced: boolean,
): RefObject<number> {
  const energyRef = useRef(0);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;

    const write = (value: number) => {
      energyRef.current = value;
      root.style.setProperty(
        "--plaza-shift",
        `${(value * MAX_SHIFT_PX).toFixed(2)}px`,
      );
      root.style.setProperty("--plaza-ghost", (value * MAX_GHOST).toFixed(3));
    };

    if (reduced) {
      write(0);
      return;
    }

    let raf = 0;
    let running = false;
    let lastY = 0;
    let lastT = 0;
    let lastScrollAt = 0;
    let energy = 0;

    const park = () => {
      running = false;
      cancelAnimationFrame(raf);
      energy = 0;
      write(0);
    };

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(Math.max(now - lastT, 1), 64);
      lastT = now;

      const y = window.scrollY;
      const v = Math.abs(y - lastY) / dt; // px per ms
      lastY = y;
      if (v > 0.01) lastScrollAt = now;

      const target = Math.min(1, v / V_MAX);
      const k = (target > energy ? ATTACK : RELEASE) * (dt / 16.7);
      energy += (target - energy) * Math.min(1, k);
      write(energy);

      if (energy < SLEEP_AT && now - lastScrollAt > SLEEP_AFTER_MS) park();
    };

    const wake = () => {
      if (running || document.hidden) return;
      running = true;
      lastY = window.scrollY;
      lastT = performance.now();
      lastScrollAt = lastT;
      raf = requestAnimationFrame(step);
    };

    const onVisibility = () => {
      if (document.hidden && running) park();
    };

    window.addEventListener("scroll", wake, { passive: true });
    document.addEventListener("visibilitychange", onVisibility);
    return () => {
      window.removeEventListener("scroll", wake);
      document.removeEventListener("visibilitychange", onVisibility);
      cancelAnimationFrame(raf);
      write(0);
    };
  }, [rootRef, reduced]);

  return energyRef;
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { azeretMono, gugi, monoton } from "./fonts";
import Hero from "./components/Hero";
import PAMarquee from "./components/PAMarquee";
import Announcements from "./components/Announcements";
import RadioWindows from "./components/RadioWindows";
import Schedule from "./components/Schedule";
import Footer from "./components/Footer";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useScrollEnergy } from "./hooks/useScrollEnergy";

/**
 * GRADIENT PLAZA — midnight mall radio.
 * A 24-hour station broadcasting from a shopping mall that only exists
 * after closing. The page is the mall at 3:33 AM: a perspective grid floor
 * that rushes when you scroll, PA announcements that smear like a
 * de-converged CRT at speed, and the booth itself — draggable retro-OS
 * windows playing a song nobody hears. No audio is ever played; the radio
 * is a picture of a sound.
 *
 * `.plaza-js` is added on mount so every enhancement (grid canvas, ticker
 * motion, absolute window positions) is JS-gated — with JavaScript disabled
 * the full page simply reads top to bottom.
 */
export default function GradientPlazaPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const energyRef = useScrollEnergy(rootRef, reduced);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("plaza-js");
    window.parent?.postMessage(
      { type: "oneshot:ready", slug: "gradient-plaza" },
      "*",
    );
  }, []);

  return (
    <div
      id="plaza-top"
      ref={rootRef}
      className={`${monoton.variable} ${gugi.variable} ${azeretMono.variable} plaza-root`}
    >
      <Hero reduced={reduced} energyRef={energyRef} />
      <PAMarquee reduced={reduced} energyRef={energyRef} />
      <main>
        <Announcements />
        <RadioWindows reduced={reduced} />
        <Schedule />
      </main>
      <Footer />
    </div>
  );
}

/* ==========================================================================
   GRADIENT PLAZA — midnight mall radio
   vaporwave · neon on deep purple · disciplined, legible, 3:33 AM forever
   Scoped by convention to .plaza-root; classes prefixed plaza-.
   ========================================================================== */

.plaza-root {
  /* -- palette (contrast measured against deep-purple #1a0b2e) ----------- */
  --plaza-void: #0d0518;      /* deepest sky, floor falloff, ticker, footer */
  --plaza-purple: #1a0b2e;    /* page background — the mall after hours */
  --plaza-panel: #241040;     /* window bodies (body text 14.3:1 on it) */
  --plaza-pink: #ff71ce;      /* accent — neon signage, ON AIR (7.5:1) */
  --plaza-cyan: #01cdfe;      /* grid light, times, controls (9.9:1) */
  --plaza-mint: #05ffa1;      /* horizon glow, live markers (14.0:1) */
  --plaza-violet: #b967ff;    /* small labels and chrome only (5.7:1) */
  --plaza-body: #efe6ff;      /* reading text (15.4:1) */
  --plaza-haze: #c7b8e0;      /* secondary text (10.0:1) */
  --plaza-line: rgba(185, 103, 255, 0.32); /* hairlines — decorative */

  /* -- aberration envelope (written live by useScrollEnergy) ------------- */
  --plaza-shift: 0px;
  --plaza-ghost: 0;

  /* -- type ---------------------------------------------------------------- */
  --plaza-font-display: var(--font-monoton), var(--font-gugi), sans-serif;
  --plaza-font-ko: var(--font-gugi), sans-serif;
  --plaza-font-mono: var(--font-azeret), var(--font-gugi), monospace;

  /* -- motion --------------------------------------------------------------- */
  --plaza-ease-out: cubic-bezier(0.16, 1, 0.3, 1);

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--plaza-purple);
  color: var(--plaza-body);
  font-family: var(--plaza-font-mono);
  font-size: clamp(15px, 1.1vw + 10px, 17px);
  line-height: 1.65;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Hangul is first-class: it always renders in Gugi (never fallback sans),
   with mono tracking turned off and words kept whole. */
.plaza-root :lang(ko) {
  font-family: var(--plaza-font-ko);
  letter-spacing: 0;
  word-break: keep-all;
}

/* The hidden attribute must win over any display we set. */
.plaza-root [hidden] {
  display: none !important;
}

/* Neon selection, scoped to the entry root */
.plaza-root ::selection {
  background: var(--plaza-pink);
  color: var(--plaza-purple);
  text-shadow: none;
}

/* Keyboard focus: cyan ring with a pink neon halo — signage, not default */
.plaza-root :focus-visible {
  outline: 2px solid var(--plaza-cyan);
  outline-offset: 3px;
  border-radius: 2px;
  box-shadow:
    0 0 0 5px rgba(255, 113, 206, 0.35),
    0 0 18px rgba(1, 205, 254, 0.55);
}

/* Screen-reader-only content (the ticker's accessible list) */
.plaza-sr {
  position: absolute;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
  border: 0;
}

/* ==========================================================================
   Chromatic aberration — .plaza-ab
   Two pseudo-element ghosts of the same text (cyan left, pink right) ride
   --plaza-shift / --plaza-ghost, which useScrollEnergy writes from scroll
   VELOCITY. mix-blend-mode: screen means the ghosts can only ADD light over
   the base glyphs — the readable text never moves and never loses contrast.
   At rest both custom properties are 0 and the heading is pixel-crisp.
   ========================================================================== */

.plaza-ab {
  position: relative;
}

.plaza-ab::before,
.plaza-ab::after {
  content: attr(data-text) / "";
  position: absolute;
  inset: 0;
  opacity: var(--plaza-ghost, 0);
  mix-blend-mode: screen;
  pointer-events: none;
  will-change: transform, opacity;
}

.plaza-ab::before {
  color: var(--plaza-cyan);
  transform: translate3d(calc(var(--plaza-shift, 0px) * -1), 0, 0);
}

.plaza-ab::after {
  color: var(--plaza-pink);
  transform: translate3d(var(--plaza-shift, 0px), 0, 0);
}

/* ==========================================================================
   Hero — the grid floor
   ========================================================================== */

.plaza-hero {
  position: relative;
  display: flex;
  align-items: flex-end;
  min-height: 100vh;
  min-height: 100svh;
  overflow: hidden;
}

/* The no-JS / pre-paint sky: same sun, same dusk, no motion. */
.plaza-hero__backdrop {
  position: absolute;
  inset: 0;
  background:
    radial-gradient(
      circle 24vmin at 50% 52%,
      rgba(255, 113, 206, 0.5),
      rgba(255, 113, 206, 0) 70%
    ),
    linear-gradient(
      180deg,
      #0d0518 0%,
      #1a0b2e 34%,
      #2b1152 57%,
      #170a31 58%,
      #0d0518 100%
    );
}

.plaza-hero__canvas {
  position: absolute;
  inset: 0;
  display: block;
  width: 100%;
  height: 100%;
}

.plaza-hero__content {
  position: relative;
  z-index: 1;
  width: 100%;
  max-width: 1240px;
  margin-inline: auto;
  padding: clamp(24px, 6vw, 72px);
  padding-bottom: clamp(56px, 11vh, 110px);
}

/* A quiet scrim so body-size hero text stays AA over the brightest
   grid lines — the neon lives behind the words, not through them. */
.plaza-hero__content::before {
  content: "";
  position: absolute;
  inset: -10% -20% -100%;
  z-index: -1;
  background: radial-gradient(
    120% 120% at 30% 80%,
