  align-items: center;
  gap: 0.6rem 1.1rem;
  margin: 0 0 1.6rem;
}

.plaza-onair {
  display: inline-flex;
  align-items: center;
  gap: 0.55em;
  padding: 0.22em 0.75em;
  border: 1px solid var(--plaza-pink);
  color: var(--plaza-pink);
  font-size: 0.85em;
  font-weight: 600;
  letter-spacing: 0.22em;
  box-shadow: 0 0 14px rgba(255, 113, 206, 0.35);
}

.plaza-onair__lamp {
  width: 0.55em;
  height: 0.55em;
  border-radius: 50%;
  background: var(--plaza-pink);
  box-shadow: 0 0 8px rgba(255, 113, 206, 0.9);
}

.plaza-js .plaza-onair__lamp {
