/* ==========================================================================
   02 · The booth — retro OS windows
   ========================================================================== */

/* No-JS: a plain column of readable panels over the tiled floor. */
.plaza-stage {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 1.6rem;
  padding: 1.6rem;
  border: 1px dashed var(--plaza-line);
  background:
    repeating-linear-gradient(
      0deg,
      rgba(185, 103, 255, 0.06) 0 1px,
      transparent 1px 32px
    ),
    repeating-linear-gradient(
      90deg,
      rgba(185, 103, 255, 0.06) 0 1px,
      transparent 1px 32px
    ),
    var(--plaza-void);
}

/* JS: the stage becomes a desktop; windows take their spawn points. */
.plaza-js .plaza-stage {
  display: block;
  position: relative;
  height: clamp(560px, 82vh, 740px);
  padding: 0;
}

.plaza-window {
  width: min(24rem, 100%);
  background: var(--plaza-panel);
  border: 1px solid var(--plaza-violet);
  box-shadow:
    8px 8px 0 rgba(13, 5, 24, 0.85),
    0 0 32px rgba(255, 113, 206, 0.14);
}

.plaza-js .plaza-window {
  position: absolute;
  width: min(24rem, calc(100% - 20px));
  will-change: transform;
}

.plaza-js .plaza-window--now {
  left: 4%;
  top: 6%;
}

.plaza-js .plaza-window--list {
  left: 48%;
  top: 16%;
  width: min(26rem, calc(100% - 20px));
}

.plaza-js .plaza-window--viz {
  left: 18%;
  top: 58%;
  width: min(28rem, calc(100% - 20px));
}

.plaza-window__bar {
  display: flex;
  align-items: stretch;
  background: linear-gradient(90deg, var(--plaza-pink), var(--plaza-violet));
  color: var(--plaza-purple); /* dark on neon: 7.5:1 → 5.7:1 across the bar */
  border-bottom: 1px solid var(--plaza-violet);
}

.plaza-window__grip {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  min-width: 0;
  padding: 0.48rem 0.75rem;
  border: 0;
  background: none;
  color: inherit;
  font: inherit;
  font-size: 0.8em;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-align: left;
  cursor: grab;
  touch-action: none;
  user-select: none;
  -webkit-user-select: none;
}

.plaza-window__grip:active {
  cursor: grabbing;
}

.plaza-window__dots {
  opacity: 0.75;
}

.plaza-window__name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.plaza-window__sys {
  width: 2.2rem;
  border: 0;
  border-left: 1px solid rgba(26, 11, 46, 0.35);
  background: none;
  color: inherit;
  font: inherit;
  font-weight: 700;
  cursor: pointer;
}

/* Instant chrome states — retro OS chrome does not ease. */
.plaza-window__sys:hover {
  background: rgba(26, 11, 46, 0.18);
}

.plaza-window__body {
  padding: 1.05rem 1.15rem 1.2rem;
}

/* -- now playing ---------------------------------------------------------- */

.plaza-now__label {
  margin: 0 0 0.7rem;
  color: var(--plaza-violet);
  font-size: 0.75em;
  letter-spacing: 0.24em;
}

.plaza-now__track {
  margin: 0;
  font-size: 1.28em;
  font-weight: 600;
  letter-spacing: 0.02em;
}

.plaza-now__trackko {
