  color: var(--plaza-haze);
}

.plaza-now__artist {
  margin: 0.45rem 0 0.95rem;
  color: var(--plaza-haze);
  font-size: 0.9em;
}

.plaza-now__progress {
  height: 8px;
  border: 1px solid var(--plaza-violet);
  background: var(--plaza-void);
  overflow: hidden;
}

.plaza-now__fill {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, var(--plaza-cyan), var(--plaza-mint));
  transform: scaleX(0.38);
  transform-origin: left center;
}

/* A 4:52 song, looping until dawn. Transform-only, JS-gated. */
.plaza-js .plaza-now__fill {
  animation: plaza-progress 292s linear infinite;
}

.plaza-now__time {
  margin: 0.5rem 0 0.95rem;
  color: var(--plaza-haze);
  font-size: 0.8em;
  letter-spacing: 0.05em;
}

.plaza-now__controls {
