}

/* -- tracklist -------------------------------------------------------------- */

.plaza-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.plaza-list__item {
  display: grid;
  grid-template-columns: auto 1fr auto;
  column-gap: 0.85rem;
  align-items: baseline;
  width: 100%;
  padding: 0.55rem 0.5rem;
  border: 0;
  border-bottom: 1px dotted var(--plaza-line);
