.plaza-sched__note {
  grid-column: 2;
  color: var(--plaza-haze);
  font-size: 0.85em;
}

@media (min-width: 800px) {
  .plaza-sched__row {
    grid-template-columns: 5.5rem 22rem 1fr;
  }

  .plaza-sched__note {
    grid-column: 3;
    align-self: baseline;
  }
}

/* The gap in the night. Pink only ever means something is wrong. */
.plaza-sched__row--lost {
  border-block: 1px dashed var(--plaza-pink);
  background: repeating-linear-gradient(
    45deg,
    rgba(255, 113, 206, 0.05) 0 8px,
    transparent 8px 16px
  );
}

.plaza-sched__row--lost .plaza-sched__time,
.plaza-sched__row--lost .plaza-sched__name {
  color: var(--plaza-pink);
  letter-spacing: 0.18em;
}

/* ==========================================================================
   Footer — end of broadcast
   ========================================================================== */

.plaza-footer {
  border-top: 1px solid var(--plaza-line);
  background: var(--plaza-void);
}

.plaza-footer__inner {
  max-width: 1240px;
  margin-inline: auto;
  padding: clamp(64px, 11vh, 120px) clamp(24px, 6vw, 72px)
    clamp(88px, 13vh, 150px);
}

.plaza-footer__stay {
  margin: 0;
  font-family: var(--plaza-font-display);
  font-weight: 400;
  font-size: clamp(1.9rem, 5.8vw, 4.1rem);
  line-height: 1.1;
  color: var(--plaza-pink);
  text-shadow:
    0 0 20px rgba(255, 113, 206, 0.5),
    0 0 70px rgba(255, 113, 206, 0.2);
}

.plaza-footer__stayko {
  margin: 0.6rem 0 2.6rem;
  font-size: clamp(1.1rem, 2.6vw, 1.7rem);
  color: var(--plaza-cyan);
}

.plaza-footer__data {
  margin: 0 0 2.4rem;
}

.plaza-footer__data div {
  display: flex;
  flex-wrap: wrap;
  gap: 0.2rem 1.2rem;
  padding: 0.5rem 0;
  border-bottom: 1px dotted var(--plaza-line);
}

.plaza-footer__data dt {
  flex: 0 0 6.5rem;
  color: var(--plaza-violet);
  font-size: 0.78em;
  letter-spacing: 0.2em;
}

.plaza-footer__data dd {
  flex: 1 1 18rem;
  margin: 0;
  font-size: 0.95em;
}

.plaza-footer__data dd [lang="ko"] {
  color: var(--plaza-haze);
}

.plaza-footer__copy {
  margin: 0;
  color: var(--plaza-haze);
  font-size: 0.9em;
}

.plaza-footer__copy [lang="ko"] {
  display: block;
  margin-top: 0.25rem;
}

/* ==========================================================================
   Small screens — the stage grows tall, windows spawn stacked but loose
   ========================================================================== */

@media (max-width: 760px) {
  .plaza-js .plaza-stage {
    height: 1080px;
  }

  .plaza-js .plaza-window--now {
    left: 3%;
    top: 2%;
  }

  .plaza-js .plaza-window--list {
    left: 6%;
    top: 34%;
  }

  .plaza-js .plaza-window--viz {
    left: 3%;
    top: 70%;
  }

  .plaza-taskbar__hint {
    flex-basis: 100%;
    margin-left: 0;
  }
}

/* ==========================================================================
   Keyframes — transform / opacity only
   ========================================================================== */

@keyframes plaza-lamp {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.35;
  }
}

@keyframes plaza-progress {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

/* ==========================================================================
   Reduced motion — one beautiful still of the mall at 3:33 AM.
   (The JS side checks the same media query: the grid draws a single frame,
   the ticker and scroll-energy loops never start, drag inertia is off.
   Dragging itself stays available — it only moves when the visitor moves.)
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .plaza-root {
    --plaza-shift: 0px;
    --plaza-ghost: 0;
  }

  .plaza-ab::before,
  .plaza-ab::after {
    content: none;
  }

  .plaza-js .plaza-onair__lamp,
  .plaza-js .plaza-now__fill {
    animation: none;
  }
}
